function minOperations(nums) {
    const max_heap = new MaxHeap(nums);
    const initial_sum = nums.reduce((acc, val) => acc + val, 0);
    const target_sum = Math.floor(initial_sum / 2);
    let sum_so_far = 0;
    let operations = 0;

    while (sum_so_far <= target_sum) {
        const largest = max_heap.pop();
        sum_so_far += Math.floor(largest / 2);
        operations++;
    }

    return operations;
}

class MaxHeap {
    constructor(elements) {
        this.heap = [];
        for (let elem of elements) {
            this.push(elem);
        }
    }

    push(val) {
        this.heap.push(val);
        this._bubbleUp();
    }

    pop() {
        if (this.heap.length === 1) return this.heap.pop();
        const max = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._sinkDown();
        return max;
    }

    _bubbleUp() {
        let idx = this.heap.length - 1;
        while (idx > 0) {
            const parentIdx = Math.floor((idx - 1) / 2);
            if (this.heap[parentIdx] >= this.heap[idx]) break;
            this._swap(idx, parentIdx);
            idx = parentIdx;
        }
    }

    _sinkDown() {
        let idx = 0;
        const length = this.heap.length;
        const element = this.heap[0];
        while (true) {
            const leftChildIdx = 2 * idx + 1;
            const rightChildIdx = 2 * idx + 2;
            let swap = null;

            if (leftChildIdx < length) {
                if (this.heap[leftChildIdx] > element) {
                    swap = leftChildIdx;
                }
            }

            if (rightChildIdx < length) {
                if ((swap === null && this.heap[rightChildIdx] > element) ||
                    (swap !== null && this.heap[rightChildIdx] > this.heap[leftChildIdx])) {
                    swap = rightChildIdx;
                }
            }

            if (swap === null) break;
            this._swap(idx, swap);
            idx = swap;
        }
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }
}
