import java.util.PriorityQueue;
import java.util.Collections;

public int minOperations(int[] nums) {
    PriorityQueue<Integer> max_heap = new PriorityQueue<>(nums.length, Collections.reverseOrder());

    int initial_sum = 0;
    for (int num : nums) {
        initial_sum += num;
        max_heap.add(num);
    }

    int target_sum = initial_sum / 2;
    int sum_so_far = 0;
    int operations = 0;

    while (sum_so_far <= target_sum) {
        int largest = max_heap.poll();
        sum_so_far += largest / 2;
        operations += 1;
    }

    return operations;
}
```


